var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 돌아올 거라고 믿어 주는 사람을 주인으로 모시고 싶다, 라......","JPN":"そう。帰ってくると信じてくれる人を主にしたい、と……","ENG":"I see... So you want to serve someone who trusts you to return...","TWN":"侍奉堅信自己會回來的人為主人……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"근사한 고백이네. 이 자리에 참석하지 않아서 듣지 못한 당사자가 안타까울 정도야.","JPN":"中々素敵な告白じゃない。本人がこの場にいなくて残念だわ。","ENG":"What a most touching declaration of your fealty. It's almost unfortunate that he's not here to hear it himself.","TWN":"真是讓人感動啊，那個人不能親耳聽到，真是可惜了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 아쉽겠어, 베로니카.","JPN":"でもお気の毒ね、ベロニカ。","ENG":"It's too bad, Veronica.","TWN":"但是非常遺憾，貝洛妮卡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그 말은 이루어질 수 없거든.","JPN":"その言葉は叶わないの。","ENG":"Because that new aspiration can't come true.","TWN":"恐怕你無法實現你的願望了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"영원히.","JPN":"永遠にね。","ENG":"Ever.","TWN":"永遠。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"리, 리코리스님! 이상한 사람들이 잔뜩 나타났슴다!","JPN":"リ、リコリス様！　変な人がいっぱい出てきたっす！","ENG":"M-Miss Lycoris! A bunch of weirdos appeared, ma'am!","TWN":"莉、莉克麗絲大人！突然出現了好多奇怪的人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저 시커먼 녀석들은 뭐야......? 맨션에 잠입해 있던 동안 한 번도 못 봤는데?","JPN":"あの真っ黒なやつらはなに……？　マンションにいる時もあんなの見たことなかったわ！","ENG":"W-who the hell are they? I never saw them the whole time I have been undercover at the Mansion!","TWN":"那些黑色東西是什麼……？我在曼森的期間從來沒見過她們啊？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"인사하렴. 이 아이들은 그레이 리프라고 한단다.","JPN":"さあ、挨拶しなさい。この子たちはグレーリーフよ。","ENG":"Say hello. I call these children the Gray Leaves.","TWN":"打個招呼吧，她們叫格雷麗芙。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"내가 배합한 식물독으로 뇌까지 가꿔 준 아이들이지.","JPN":"私が配合した植物毒で脳の髄まで綺麗に育てあげたの。","ENG":"I've personally tended to their brains with my plant poison concoction.","TWN":"我用親自調配的植物毒液重新培養了她們的大腦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 사람들은......","JPN":"その方たちは……","ENG":"They are...","TWN":"這些人……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"활동 중에 실종됐다고 알려진 전대 메이드장들이군요.","JPN":"活動中に失踪したと言われた先代のメイド長たちですね。","ENG":"They are the former Chief Maids who supposedly went missing during their service.","TWN":"是執行任務時，所失蹤的前任女僕長們。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"설마 당신이 그녀들을 숨겨두고 있던 겁니까?","JPN":"まさかあなたが彼女たちを……？","ENG":"So you were hiding them?","TWN":"原來你一直把她們藏起來了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"눈썰미가 좋구나.","JPN":"さすがだわ。","ENG":"How observant of you.","TWN":"不笨嘛。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"재능은 가졌지만 가망이 없던 아이들에게 새로운 쓰임새를 만들어 준 거지.","JPN":"才能はあるけど見込みがなかった子に、新しい使い道を切り開いてあげたのよ。","ENG":"I've given new purpose to those who were talented but weren't quite promising enough.","TWN":"她們雖然有才華，但她們沒有任何可能性，所以我賜予了她們全新的角色。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"가망?","JPN":"見込み？","ENG":"Promising enough for what?","TWN":"可能性？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"맨션의 차기 주인이 될 가능성 말이야.","JPN":"マンションの次期主になる可能性のことよ。","ENG":"To become the next Master of the Mansion.","TWN":"成為曼森下一個主人的可能性。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};